import{_ as o,C as n,o as s,c as l,E as i,w as r,a as t,a0 as c}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to France","description":"Immigration pathways and relocation guide for France","frontmatter":{"layout":"doc","title":"Moving to France","description":"Immigration pathways and relocation guide for France"},"headers":[],"relativePath":"europe/france/moving-there.md","filePath":"europe/france/moving-there.md","lastUpdated":null}'),d={name:"europe/france/moving-there.md"};function h(m,e,u,g,f,p){const a=n("Badge");return s(),l("div",null,[i(a,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[t("EU/EEA: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[t("Non-EU: Long-Stay Visa",-1)])]),_:1}),e[2]||(e[2]=c('<h1 id="moving-to-france" tabindex="-1">Moving to France <a class="header-anchor" href="#moving-to-france" aria-label="Permalink to &quot;Moving to France&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><p>Free movement applies. If staying more than 3 months, register at the local préfecture. No residence card is required but proof of employment, study, or resources must be demonstrated.</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">​</a></h3><p>Post-Brexit, UK citizens need a long-stay visa (VLS-TS) for stays over 90 days unless covered by the Withdrawal Agreement (resided in France before 31 December 2020).</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Long-Stay Visa (VLS-TS)</strong>: For employment, study, or family reunification. Valid for 1 year, renewable.</li><li><strong>Talent Passport</strong>: For highly skilled workers, researchers, artists, and entrepreneurs. Fast-track processing.</li><li><strong>EU Blue Card</strong>: For highly skilled workers with a salary threshold (~€53,000/year in 2025).</li><li><strong>Student Visa</strong>: For university studies. Part-time work permitted (964 hours/year).</li><li><strong>Family Reunification</strong>: For spouses and minor children.</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>France does not have a dedicated digital nomad visa. Remote workers can apply for the <strong>Talent Passport (Profession Libérale)</strong> for self-employed professionals, or the <strong>VLS-TS Visiteur</strong> if you have sufficient resources (no work allowed). The latter is suitable for retirees or those with passive income.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] Obtain necessary visa (non-EU)</li><li>[ ] Arrange health insurance (private until registered with PUMA)</li><li>[ ] Research housing (Paris is expensive; Lyon, Bordeaux, Montpellier more affordable)</li><li>[ ] Gather medical records and HRT documentation (translated to French)</li><li>[ ] Learn basic French (essential for administration)</li><li>[ ] Notify your bank and redirect mail</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Validate your visa at the OFII (French Immigration Office) within 3 months</li><li>[ ] Apply for a residence card (carte de séjour) if staying long-term</li><li>[ ] Register with PUMA (health insurance) after 3 months of stable residence</li><li>[ ] Open a French bank account</li><li>[ ] Find a GP (médecin traitant) — declare one for best reimbursement</li><li>[ ] Apply for a French SIM card (Free, Orange, SFR)</li><li>[ ] Connect with OUTrans or Acceptess-T for trans community support</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li>Monthly rent (1-bed): €800-1,500 (Paris), €500-900 (other cities)</li><li>Monthly budget (single person): €800-1,400 excluding rent</li><li>Public transport: €85/month (Paris Navigo), €30-60 (other cities)</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><p>Varies by region: Mediterranean south (hot summers, mild winters), oceanic west (mild, rainy), continental east (cold winters, warm summers).</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>French is the official language. English proficiency varies — higher in Paris and tourist areas, lower in rural regions. Learning French is strongly recommended for administration, healthcare, and social integration.</p>',22))])}const v=o(d,[["render",h]]);export{b as __pageData,v as default};
